// PUT endpoint to update a document
router.put('/documents/:id', authorizeDocumentAccess, checkUserRole('admin'), async (req, res) => {
  try {
    // Allowlist fields that can be updated
    const allowedUpdates = ['title', 'content'];
    const updates = Object.keys(req.body);
    const isValidOperation = updates.every(update => allowedUpdates.includes(update));

    if (!isValidOperation) {
      return res.status(400).json({ error: 'Invalid updates' });
    }

    updates.forEach(update => req.document[update] = req.body[update]);
    await req.document.save();
    res.json(req.document);
  } catch (error) {
    res.status(500).json({ error: 'Server error' });
  }
});

